class Solution:
    def sequentialDigits(self, low: int, high: int) -> List[int]:
        digits = list(range(10))
        result = []
        for i in range(len(digits)):
            for j in range(i + 1, len(digits) + 1):
                num = int("".join(map(str, digits[i:j])))
                if low <= num <= high:
                    result.append(num)
